'use client'

import { useState, useRef, useEffect, useCallback } from 'react'
import { X, Plus, Maximize2, Minimize2 } from 'lucide-react'

export function Terminal() {
  const [sessions, setSessions] = useState([])
  const [activeSessionId, setActiveSessionId] = useState(null)
  const [devices, setDevices] = useState([])
  const [showDeviceList, setShowDeviceList] = useState(false)
  const [history, setHistory] = useState([])
  const [historyIndex, setHistoryIndex] = useState(-1)
  const [isFullscreen, setIsFullscreen] = useState(false)

  const terminalRef = useRef(null)
  const inputRef = useRef(null)

  const vendorCommands = {
    huawei: [
      'display', 'display version', 'display interface', 'display ip interface',
      'display vlan', 'display mac-address', 'display arp', 'display cpu',
      'display memory', 'display current-configuration', 'display device',
      'display environment', 'display alarm', 'display logbuffer',
      'system-view', 'interface', 'quit', 'return', 'undo', 'save',
      'reboot', 'ping', 'tracert', 'telnet', 'ssh',
      'sysname', 'vlan', 'port', 'description', 'shutdown', 'undo shutdown',
      'ip address', 'ntp', 'snmp', 'aaa', 'local-user', 'password'
    ],
    mikrotik: [
      'interface', 'interface print', 'interface enable', 'interface disable',
      'ip address', 'ip address print', 'ip route', 'ip route print',
      'ip firewall', 'ip firewall filter', 'ip firewall nat',
      'ip dhcp-server', 'ip dns', 'ping', 'traceroute',
      'system', 'system identity', 'system reboot', 'system resource print',
      'user', 'user print', 'export', 'log', 'log print',
      'queue', 'queue simple', 'queue tree'
    ],
    cisco: [
      'show', 'show version', 'show running-config', 'show interface',
      'show ip interface', 'show vlan', 'show mac address-table',
      'show ip route', 'show logging', 'configure terminal',
      'interface', 'no', 'end', 'exit', 'write',
      'ping', 'traceroute', 'hostname', 'vlan', 'switchport'
    ],
    linux: [
      'ls', 'ls -la', 'ls -l', 'cd', 'pwd', 'mkdir', 'rm', 'rm -rf',
      'cp', 'mv', 'cat', 'head', 'tail', 'tail -f', 'grep', 'find',
      'ps', 'ps aux', 'top', 'kill', 'systemctl', 'systemctl status',
      'journalctl', 'ip', 'ip addr', 'ip route', 'ping', 'traceroute',
      'df', 'df -h', 'du', 'free', 'uptime', 'vi', 'nano', 'exit'
    ]
  }

  useEffect(() => {
    fetch('/devices/api/list/')
      .then(res => res.json())
      .then(data => {
        const deviceList = data.devices || data || []
        setDevices(deviceList.map(d => ({
          id: d.id,
          name: d.hostname || d.name,
          ip: d.ip_address || d.ip,
          vendor: (d.vendor || 'linux').toLowerCase(),
          username: d.username || 'admin',
          port: d.port || 22
        })))
      })
      .catch(err => {
        console.error('Erro ao carregar dispositivos:', err)
        setDevices([])
      })
  }, [])

  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight
    }
  }, [sessions])

  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.focus()
    }
  }, [activeSessionId])

  const activeSession = sessions.find(s => s.id === activeSessionId)

  const getPrompt = (device) => {
    const vendor = device.vendor?.toLowerCase() || 'linux'
    switch (vendor) {
      case 'huawei':
        return '<' + device.name + '>'
      case 'mikrotik':
        return '[' + device.username + '@' + device.name + '] >'
      case 'cisco':
        return device.name + '#'
      case 'linux':
        return device.username + '@' + device.name + ':~$'
      default:
        return device.name + '>'
    }
  }

  const getCompletions = useCallback((partial, vendor) => {
    const commands = vendorCommands[vendor] || vendorCommands.linux
    const parts = partial.split(' ')
    const lastPart = parts[parts.length - 1].toLowerCase()

    if (lastPart.length === 0) return []

    const matches = commands.filter(cmd => {
      if (parts.length > 1) {
        const prefix = parts.slice(0, -1).join(' ').toLowerCase()
        return cmd.toLowerCase().startsWith(prefix + ' ' + lastPart)
      }
      return cmd.toLowerCase().startsWith(lastPart)
    })

    return matches.slice(0, 10)
  }, [])

  const simulateCommand = (command, device) => {
    const cmd = command.toLowerCase().trim()

    if (device.vendor === 'huawei') {
      if (cmd === 'display version') {
        return [
          'Huawei Versatile Routing Platform Software',
          'VRP (R) software, Version 5.170',
          'Copyright (C) Huawei Technologies Co., Ltd.',
          'Uptime is 125 days, 14 hours, 32 minutes'
        ]
      }
      if (cmd === 'display cpu') {
        return ['CPU Usage: 15.6%', 'CPU utilization for five seconds: 15%', 'CPU utilization for one minute: 18%']
      }
      if (cmd === 'display interface') {
        return ['GigabitEthernet0/0/1 current state: UP', 'Line protocol current state: UP']
      }
      if (cmd === 'display vlan') {
        return ['VLAN ID: 1, Name: default', 'VLAN ID: 100, Name: Clientes']
      }
    }

    if (device.vendor === 'mikrotik') {
      if (cmd === 'interface print') {
        return [
          'Flags: D - dynamic, X - disabled, R - running',
          ' #    NAME                           TYPE       ACTUAL-MTU',
          ' 0  R ether1                         ether            1500',
          ' 1  R ether2                         ether            1500'
        ]
      }
      if (cmd === 'system resource print') {
        return ['uptime: 45d3h27m', 'version: 7.12.1 (stable)', 'cpu-load: 12%', 'free-memory: 412MiB']
      }
    }

    if (device.vendor === 'linux') {
      if (cmd === 'ls -la') {
        return ['total 48', 'drwxr-xr-x  6 root root 4096 Jan 15 10:32 .']
      }
      if (cmd === 'df -h') {
        return ['Filesystem      Size  Used Avail Use% Mounted on', '/dev/sda1       50G   20G   30G  40% /']
      }
    }

    return ["Comando '" + command + "' executado em " + device.name]
  }

  const connectToDevice = (device) => {
    const sessionId = 'session-' + Date.now()
    const newSession = {
      id: sessionId,
      device: device,
      output: [
        '═══════════════════════════════════════════════════════════════',
        '  Conectando a ' + device.name + ' (' + device.ip + ')...',
        '═══════════════════════════════════════════════════════════════',
        '',
        '  Vendor: ' + device.vendor.toUpperCase(),
        '  IP: ' + device.ip + ':' + device.port,
        '  Usuario: ' + device.username,
        ''
      ],
      status: 'connecting'
    }

    setSessions(prev => [...prev, newSession])
    setActiveSessionId(sessionId)
    setShowDeviceList(false)

    setTimeout(() => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return {
            ...s,
            status: 'connected',
            output: [...s.output, 'Conexao estabelecida com sucesso!', '', getPrompt(device)]
          }
        }
        return s
      }))
    }, 1000)
  }

  const processCommand = (command) => {
    if (!activeSession) return

    if (command.trim()) {
      setHistory(prev => [...prev, command])
      setHistoryIndex(-1)
    }

    if (command.toLowerCase() === 'exit' || command.toLowerCase() === 'quit') {
      closeSession(activeSession.id)
      return
    }

    if (command.toLowerCase() === 'clear') {
      setSessions(prev => prev.map(s => {
        if (s.id === activeSession.id) {
          return { ...s, output: [getPrompt(s.device)] }
        }
        return s
      }))
      return
    }

    const output = simulateCommand(command, activeSession.device)
    setSessions(prev => prev.map(s => {
      if (s.id === activeSession.id) {
        return {
          ...s,
          output: [...s.output, command, ...output, '', getPrompt(s.device)]
        }
      }
      return s
    }))
  }

  const closeSession = (sessionId) => {
    setSessions(prev => prev.filter(s => s.id !== sessionId))
    if (activeSessionId === sessionId) {
      const remaining = sessions.filter(s => s.id !== sessionId)
      setActiveSessionId(remaining.length > 0 ? remaining[0].id : null)
    }
  }

  const handleKeyDown = (e) => {
    // TAB - Autocomplete (CORREÇÃO: preventDefault impede navegador de capturar)
    if (e.key === 'Tab') {
      e.preventDefault()
      e.stopPropagation()

      if (activeSession && inputRef.current) {
        const currentCommand = inputRef.current.value
        const completions = getCompletions(currentCommand, activeSession.device.vendor)

        if (completions.length === 1) {
          inputRef.current.value = completions[0] + ' '
        } else if (completions.length > 1) {
          const completionList = completions.join('  ')
          setSessions(prev => prev.map(s => {
            if (s.id === activeSession.id) {
              return {
                ...s,
                output: [...s.output, currentCommand, '', 'Opcoes: ' + completionList, '', getPrompt(s.device)]
              }
            }
            return s
          }))
        }
      }
      return false
    }

    // Enter - Executar comando
    if (e.key === 'Enter') {
      e.preventDefault()
      if (inputRef.current && activeSession) {
        const command = inputRef.current.value
        inputRef.current.value = ''
        processCommand(command)
      }
      return false
    }

    // Seta para cima - Historico anterior
    if (e.key === 'ArrowUp') {
      e.preventDefault()
      if (history.length > 0 && historyIndex < history.length - 1) {
        const newIndex = historyIndex + 1
        setHistoryIndex(newIndex)
        if (inputRef.current) {
          inputRef.current.value = history[history.length - 1 - newIndex]
        }
      }
      return false
    }

    // Seta para baixo - Proximo do historico
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      if (historyIndex > 0) {
        const newIndex = historyIndex - 1
        setHistoryIndex(newIndex)
        if (inputRef.current) {
          inputRef.current.value = history[history.length - 1 - newIndex]
        }
      } else if (historyIndex === 0) {
        setHistoryIndex(-1)
        if (inputRef.current) {
          inputRef.current.value = ''
        }
      }
      return false
    }

    // Ctrl+C - Cancelar
    if (e.key === 'c' && e.ctrlKey) {
      e.preventDefault()
      if (inputRef.current) {
        inputRef.current.value = ''
      }
      if (activeSession) {
        setSessions(prev => prev.map(s => {
          if (s.id === activeSession.id) {
            return { ...s, output: [...s.output, '^C', '', getPrompt(s.device)] }
          }
          return s
        }))
      }
      return false
    }

    // Ctrl+L - Limpar tela
    if (e.key === 'l' && e.ctrlKey) {
      e.preventDefault()
      if (activeSession) {
        setSessions(prev => prev.map(s => {
          if (s.id === activeSession.id) {
            return { ...s, output: [getPrompt(s.device)] }
          }
          return s
        }))
      }
      return false
    }
  }

  return (
    <div className={'h-full flex flex-col' + (isFullscreen ? ' fixed inset-0 z-50 bg-black' : '')}>
      <div className="flex items-center justify-between bg-card border-b border-border px-4 py-3">
        <div className="flex items-center gap-3">
          <h1 className="text-xl font-bold">Terminal SSH</h1>
          <button onClick={() => setShowDeviceList(!showDeviceList)} className="flex items-center gap-2 px-3 py-1.5 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors">
            <Plus className="w-4 h-4" />
            Nova Conexao
          </button>
        </div>
        <button onClick={() => setIsFullscreen(!isFullscreen)} className="p-2 rounded-lg hover:bg-accent transition-colors">
          {isFullscreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
        </button>
      </div>

      {showDeviceList && (
        <div className="absolute top-16 left-4 z-50 bg-card border border-border rounded-lg shadow-xl p-4 w-80">
          <h3 className="font-semibold mb-3">Selecione um dispositivo</h3>
          <div className="space-y-2 max-h-64 overflow-auto">
            {devices.length === 0 ? (
              <p className="text-muted-foreground text-sm">Nenhum dispositivo cadastrado</p>
            ) : (
              devices.map(device => (
                <button key={device.id} onClick={() => connectToDevice(device)} className="w-full flex items-center gap-3 p-2 rounded-lg hover:bg-accent transition-colors text-left">
                  <div className={'w-2 h-2 rounded-full ' + (device.vendor === 'huawei' ? 'bg-red-500' : device.vendor === 'mikrotik' ? 'bg-green-500' : device.vendor === 'cisco' ? 'bg-blue-500' : 'bg-yellow-500')} />
                  <div>
                    <div className="font-medium">{device.name}</div>
                    <div className="text-xs text-muted-foreground">{device.ip} ({device.vendor})</div>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {sessions.length > 0 && (
        <div className="flex bg-muted/50 border-b border-border overflow-x-auto">
          {sessions.map(session => (
            <div key={session.id} onClick={() => setActiveSessionId(session.id)} className={'flex items-center gap-2 px-4 py-2 border-r border-border cursor-pointer transition-colors ' + (activeSessionId === session.id ? 'bg-background' : 'hover:bg-accent')}>
              <div className={'w-2 h-2 rounded-full ' + (session.status === 'connected' ? 'bg-green-500' : session.status === 'connecting' ? 'bg-yellow-500 animate-pulse' : 'bg-red-500')} />
              <span className="text-sm font-medium whitespace-nowrap">{session.device.name}</span>
              <button onClick={(e) => { e.stopPropagation(); closeSession(session.id); }} className="p-0.5 rounded hover:bg-destructive/20 transition-colors">
                <X className="w-3 h-3" />
              </button>
            </div>
          ))}
        </div>
      )}

      <div ref={terminalRef} className="flex-1 bg-black text-white font-mono text-sm overflow-auto p-4" onClick={() => inputRef.current?.focus()}>
        {sessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-400">
            <p className="text-lg mb-2">Nenhuma sessao ativa</p>
            <p className="text-sm">Clique em Nova Conexao para comecar</p>
          </div>
        ) : activeSession ? (
          <>
            {activeSession.output.map((line, idx) => (
              <div key={idx} className="whitespace-pre-wrap break-all">{line}</div>
            ))}
            <div className="flex items-center">
              <span className="text-green-400 mr-2">{getPrompt(activeSession.device)}</span>
              <input ref={inputRef} type="text" className="flex-1 bg-transparent outline-none border-none text-white" onKeyDown={handleKeyDown} autoFocus spellCheck={false} autoComplete="off" autoCapitalize="off" tabIndex={0} />
            </div>
          </>
        ) : null}
      </div>

      {activeSession && (
        <div className="flex items-center justify-between bg-card border-t border-border px-4 py-1.5 text-xs text-muted-foreground">
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-1.5">
              <div className={'w-2 h-2 rounded-full ' + (activeSession.status === 'connected' ? 'bg-green-500' : 'bg-yellow-500')} />
              {activeSession.status === 'connected' ? 'Conectado' : 'Conectando...'}
            </span>
            <span>{activeSession.device.name} ({activeSession.device.ip})</span>
          </div>
          <span>TAB: autocompletar | setas: historico | Ctrl+C: cancelar | Ctrl+L: limpar</span>
        </div>
      )}
    </div>
  )
}
